 71→/**
 72→ * Get AI investment by project - where is time being spent?
 73→ */
 74→export async function getProjectInvestment(
 75→	orgId: string,
 76→	params: {
 77→		days?: number;
 78→		limit?: number;
 79→		offset?: number;
 80→		project_path?: string;
 81→		project_paths?: string[];
 82→	} = {},
 83→): Promise<ProjectInvestment[]> {
 84→	const {
 85→		days = 30,
 86→		limit = 20,
 87→		offset = 0,
 88→		project_path,
 89→		project_paths,
 90→	} = params;
 91→	const org = escapeString(orgId);
 92→	const d = Number(days);
 93→	const lim = Number(limit);
 94→	const off = Number(offset);
 95→
 96→	let projectFilter = "";
 97→	if (project_path) {
 98→		projectFilter = `AND project_path = '${escapeString(project_path)}'`;
 99→	} else if (project_paths && project_paths.length > 0) {
100→		const escaped = project_paths.map((p) => `'${escapeString(p)}'`).join(", ");
101→		projectFilter = `AND project_path IN (${escaped})`;
102→	}
103→
104→	const query = `
105→    WITH current_period AS (
106→      SELECT
107→        if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as project_key,
108→        any(git_remote) as _git_remote,
109→        any(project_path) as project_path,
110→        COUNT(*) as sessions,
111→        COUNT(DISTINCT user_id) as unique_users,
112→        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
113→        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
114→        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
115→        round(SUM(actual_duration_min), 2) as total_duration_min,
116→        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
117→        round(AVG(success_score), 2) as success_rate
118→      FROM rudel.session_analytics
119→      WHERE ${buildDateFilter(d)}
120→        AND organization_id = '${org}'
121→        AND (git_remote != '' OR package_name != '' OR project_path != '')
122→        ${projectFilter}
123→      GROUP BY project_key
124→    ),
125→    previous_period AS (
126→      SELECT
127→        if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as project_key,
128→        round(AVG(success_score), 2) as prev_success_rate
129→      FROM rudel.session_analytics
130→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
131→        AND session_date < now64(3) - INTERVAL ${d} DAY
132→        AND organization_id = '${org}'
133→        AND (git_remote != '' OR package_name != '' OR project_path != '')
134→        ${projectFilter}
135→      GROUP BY project_key
136→    )
137→    SELECT
138→      c.project_key as repository,
139→      c._git_remote as git_remote,
140→      c.project_path,
141→      c.sessions,
142→      c.unique_users,
143→      c.total_tokens,
144→      c.input_tokens_sum as input_tokens,
145→      c.output_tokens_sum as output_tokens,
146→      c.total_duration_min,
147→      c.avg_session_duration_min,
148→      c.success_rate,
149→      round((c.output_tokens_sum / 1000000.0) * 15.0 + (c.input_tokens_sum / 1000000.0) * 3.0, 4) as cost,
150→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
151→    FROM current_period c
152→    LEFT JOIN previous_period p ON c.project_key = p.project_key
153→    ORDER BY c.total_duration_min DESC
154→    LIMIT ${lim}
155→    OFFSET ${off}
156→  `;
157→
158→	const results = await queryClickhouse<
159→		ProjectInvestment & { git_remote?: string }
160→	>(query);
161→
162→	return results.map((project) => ({
163→		...project,
164→		repository: project.repository || null,
165→		git_remote: project.git_remote || undefined,
166→	}));
167→}
