169→/**
170→ * Get knowledge silos - projects with only one developer
171→ */
172→export async function getKnowledgeSilos(
173→	orgId: string,
174→	params: { days?: number; min_sessions?: number } = {},
175→): Promise<KnowledgeSilo[]> {
176→	const { days = 30, min_sessions = 5 } = params;
177→	const org = escapeString(orgId);
178→	const d = Number(days);
179→	const minSess = Number(min_sessions);
180→
181→	const query = `
182→    SELECT
183→      project_path,
184→      any(user_id) as sole_user,
185→      COUNT(*) as sessions,
186→      CASE
187→        WHEN COUNT(*) >= 20 THEN 'high'
188→        WHEN COUNT(*) >= 10 THEN 'medium'
189→        ELSE 'low'
190→      END as risk_level
191→    FROM rudel.session_analytics
192→    WHERE ${buildDateFilter(d)}
193→      AND organization_id = '${org}'
194→      AND project_path != ''
195→    GROUP BY project_path
196→    HAVING COUNT(DISTINCT user_id) = 1
197→      AND COUNT(*) >= ${minSess}
198→    ORDER BY sessions DESC
199→  `;
200→
201→	const results = await queryClickhouse<KnowledgeSilo>(query);
202→
203→	return results.map((silo) => ({
204→		...silo,
205→		project_name: extractProjectName(silo.project_path),
206→		repository_name: extractRepositoryName(silo.project_path),
207→	}));
208→}
