210→/**
211→ * Get project activity trend over time
212→ */
213→export async function getProjectActivity(
214→	orgId: string,
215→	projectPath: string,
216→	params: { days?: number; granularity?: "day" | "week" | "month" } = {},
217→): Promise<ProjectActivity[]> {
218→	const { days = 30, granularity = "day" } = params;
219→	const org = escapeString(orgId);
220→	const pp = escapeString(projectPath);
221→	const d = Number(days);
222→
223→	let dateGrouping = "toDate(session_date)";
224→	if (granularity === "week") {
225→		dateGrouping = "toMonday(session_date)";
226→	} else if (granularity === "month") {
227→		dateGrouping = "toStartOfMonth(session_date)";
228→	}
229→
230→	const query = `
231→    WITH project_key AS (
232→      SELECT if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as pk, any(project_path) as project_path
233→      FROM rudel.session_analytics
234→      WHERE project_path = '${pp}'
235→        AND (git_remote != '' OR package_name != '' OR project_path != '')
236→        AND organization_id = '${org}'
237→      LIMIT 1
238→    )
239→    SELECT
240→      toString(${dateGrouping}) as date,
241→      pk.project_path,
242→      COUNT(*) as sessions,
243→      COUNT(DISTINCT s.user_id) as unique_users
244→    FROM project_key pk
245→    INNER JOIN rudel.session_analytics s ON if(s.git_remote != '', s.git_remote, if(s.package_name != '', s.package_name, s.project_path)) = pk.pk
246→    WHERE s.${buildDateFilter(d)}
247→      AND s.organization_id = '${org}'
248→    GROUP BY ${dateGrouping}, pk.project_path
249→    ORDER BY date ASC
250→  `;
251→
252→	return queryClickhouse<ProjectActivity>(query);
253→}
