255→/**
256→ * Get project summary statistics
257→ */
258→export async function getProjectSummary(
259→	orgId: string,
260→	days = 30,
261→): Promise<ProjectSummary> {
262→	const org = escapeString(orgId);
263→	const d = Number(days);
264→
265→	const query = `
266→    WITH project_stats AS (
267→      SELECT
268→        project_path,
269→        COUNT(*) as sessions,
270→        COUNT(DISTINCT user_id) as users
271→      FROM rudel.session_analytics
272→      WHERE ${buildDateFilter(d)}
273→        AND organization_id = '${org}'
274→        AND project_path != ''
275→      GROUP BY project_path
276→    )
277→    SELECT
278→      COUNT(*) as total_projects,
279→      countIf(users = 1 AND sessions >= 5) as projects_with_silos,
280→      round(AVG(users), 2) as avg_users_per_project,
281→      argMax(project_path, sessions) as most_active_project,
282→      max(sessions) as most_active_sessions
283→    FROM project_stats
284→  `;
285→
286→	const result = await queryClickhouse<ProjectSummary>(query);
287→	return (
288→		result[0] || {
289→			total_projects: 0,
290→			projects_with_silos: 0,
291→			avg_users_per_project: 0,
292→			most_active_project: "",
293→			most_active_sessions: 0,
294→		}
295→	);
296→}
