298→/**
299→ * Get detailed metrics for a specific project
300→ */
301→export async function getProjectDetails(
302→	orgId: string,
303→	projectPath: string,
304→	days = 30,
305→): Promise<ProjectDetails | null> {
306→	const org = escapeString(orgId);
307→	const pp = escapeString(projectPath);
308→	const d = Number(days);
309→
310→	const query = `
311→    WITH project_key AS (
312→      SELECT if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as pk
313→      FROM rudel.session_analytics
314→      WHERE project_path = '${pp}'
315→        AND (git_remote != '' OR package_name != '' OR project_path != '')
316→        AND organization_id = '${org}'
317→      LIMIT 1
318→    )
319→    SELECT
320→      any(project_path) as project_path,
321→      COUNT(*) as total_sessions,
322→      SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
323→      SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
324→      SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
325→      COUNT(DISTINCT user_id) as contributors_count,
326→      countIf(success_score < 40) as errors_count,
327→      round(AVG(actual_duration_min), 2) as avg_session_duration_min,
328→      round(AVG(success_score), 2) as success_rate,
329→      round(SUM(actual_duration_min), 2) as total_duration_min
330→    FROM rudel.session_analytics
331→    WHERE if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) = (SELECT pk FROM project_key)
332→    AND ${buildDateFilter(d)}
333→    AND organization_id = '${org}'
334→  `;
335→
336→	const results = await queryClickhouse<
337→		ProjectDetails & {
338→			input_tokens_sum: number;
339→			output_tokens_sum: number;
340→		}
341→	>(query);
342→
343→	const [row] = results;
344→	if (!row) return null;
345→	const cost =
346→		row.output_tokens_sum * 0.000015 + row.input_tokens_sum * 0.000003;
347→	return {
348→		project_path: row.project_path,
349→		total_sessions: row.total_sessions,
350→		total_tokens: row.total_tokens,
351→		contributors_count: row.contributors_count,
352→		errors_count: row.errors_count,
353→		avg_session_duration_min: row.avg_session_duration_min,
354→		success_rate: row.success_rate,
355→		total_duration_min: row.total_duration_min,
356→		cost: parseFloat(cost.toFixed(4)),
357→	};
358→}
