414→): Promise<ProjectFeatureUsage> {
415→	const org = escapeString(orgId);
416→	const pp = escapeString(projectPath);
417→	const d = Number(days);
418→
419→	const pkSubquery = `(
420→    SELECT if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as pk
421→    FROM rudel.session_analytics
422→    WHERE project_path = '${pp}'
423→      AND (git_remote != '' OR package_name != '' OR project_path != '')
424→      AND organization_id = '${org}'
425→    LIMIT 1
426→  )`;
427→
428→	const adoptionQuery = `
429→    SELECT
430→      COUNT(*) as total_sessions,
431→      countIf(length(subagent_types) > 0) as subagents_sessions,
432→      countIf(length(skills) > 0) as skills_sessions,
433→      countIf(length(slash_commands) > 0) as slash_commands_sessions
434→    FROM rudel.session_analytics
435→    WHERE if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) = ${pkSubquery}
436→    AND ${buildDateFilter(d)}
437→    AND organization_id = '${org}'
438→  `;
439→
440→	const topSubagentsQuery = `
441→    SELECT val as name, count() as count
442→    FROM rudel.session_analytics
443→    ARRAY JOIN subagent_types as val
444→    WHERE if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) = ${pkSubquery}
445→      AND ${buildDateFilter(d)}
446→      AND organization_id = '${org}'
447→      AND val != ''
448→    GROUP BY val
449→    ORDER BY count DESC
450→    LIMIT 10
451→  `;
452→
453→	const topSkillsQuery = `
454→    SELECT val as name, count() as count
455→    FROM rudel.session_analytics
456→    ARRAY JOIN skills as val
457→    WHERE if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) = ${pkSubquery}
458→      AND ${buildDateFilter(d)}
459→      AND organization_id = '${org}'
460→      AND val != ''
461→    GROUP BY val
462→    ORDER BY count DESC
463→    LIMIT 10
464→  `;
465→
466→	const topSlashCommandsQuery = `
467→    SELECT val as name, count() as count
468→    FROM rudel.session_analytics
469→    ARRAY JOIN slash_commands as val
470→    WHERE if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) = ${pkSubquery}
471→      AND ${buildDateFilter(d)}
472→      AND organization_id = '${org}'
473→      AND val != ''
474→    GROUP BY val
475→    ORDER BY count DESC
476→    LIMIT 10
477→  `;
478→
479→	const [adoptionResults, topSubagents, topSkills, topSlashCommands] =
480→		await Promise.all([
481→			queryClickhouse<{
482→				total_sessions: number;
483→				subagents_sessions: number;
484→				skills_sessions: number;
485→				slash_commands_sessions: number;
486→			}>(adoptionQuery),
487→			queryClickhouse<{ name: string; count: number }>(topSubagentsQuery),
488→			queryClickhouse<{ name: string; count: number }>(topSkillsQuery),
489→			queryClickhouse<{ name: string; count: number }>(topSlashCommandsQuery),
490→		]);
491→
492→	if (adoptionResults.length === 0) {
493→		return {
494→			subagents_adoption_rate: 0,
495→			skills_adoption_rate: 0,
496→			slash_commands_adoption_rate: 0,
497→			top_subagents: [],
498→			top_skills: [],
499→			top_slash_commands: [],
500→		};
501→	}
502→
503→	const [stats] = adoptionResults;
504→	if (!stats)
505→		return {
506→			subagents_adoption_rate: 0,
507→			skills_adoption_rate: 0,
508→			slash_commands_adoption_rate: 0,
509→			top_subagents: [],
510→			top_skills: [],
511→			top_slash_commands: [],
512→		};
513→	return {
514→		subagents_adoption_rate:
515→			stats.total_sessions > 0
516→				? (stats.subagents_sessions / stats.total_sessions) * 100
517→				: 0,
518→		skills_adoption_rate:
519→			stats.total_sessions > 0
520→				? (stats.skills_sessions / stats.total_sessions) * 100
521→				: 0,
522→		slash_commands_adoption_rate:
523→			stats.total_sessions > 0
524→				? (stats.slash_commands_sessions / stats.total_sessions) * 100
525→				: 0,
526→		top_subagents: topSubagents,
527→		top_skills: topSkills,
528→		top_slash_commands: topSlashCommands,
529→	};
530→}
