535→export async function getProjectErrors(
536→	orgId: string,
537→	projectPath: string,
538→	days = 30,
539→): Promise<ProjectError[]> {
540→	const org = escapeString(orgId);
541→	const pp = escapeString(projectPath);
542→	const d = Number(days);
543→
544→	const query = `
545→    WITH project_key AS (
546→      SELECT if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) as pk
547→      FROM rudel.session_analytics
548→      WHERE project_path = '${pp}'
549→        AND (git_remote != '' OR package_name != '' OR project_path != '')
550→        AND organization_id = '${org}'
551→      LIMIT 1
552→    ),
553→    error_extracts AS (
554→      SELECT
555→        session_id,
556→        user_id,
557→        session_date,
558→        CASE
559→          WHEN content LIKE '%OperationFailed%' THEN 'OperationFailed'
560→          WHEN content LIKE '%UnknownError%' THEN 'UnknownError'
561→          WHEN content LIKE '%ORPCError%' THEN 'ORPCError'
562→          WHEN content LIKE '%TimeoutError%' THEN 'TimeoutError'
563→          WHEN content LIKE '%TypeError%' THEN 'TypeError'
564→          WHEN content LIKE '%ReferenceError%' THEN 'ReferenceError'
565→          WHEN content LIKE '%Error:%' OR content LIKE '%error:%' THEN 'GenericError'
566→          ELSE NULL
567→        END as error_pattern
568→      FROM rudel.session_analytics
569→      WHERE if(git_remote != '', git_remote, if(package_name != '', package_name, project_path)) = (SELECT pk FROM project_key)
570→        AND ${buildDateFilter(d)}
571→        AND organization_id = '${org}'
572→        AND (content LIKE '%Error:%' OR content LIKE '%error:%')
573→    )
574→    SELECT
575→      error_pattern,
576→      COUNT(*) as occurrences,
577→      uniq(user_id) as affected_users,
578→      toString(min(session_date)) as first_seen,
579→      toString(max(session_date)) as last_seen
580→    FROM error_extracts
581→    WHERE error_pattern IS NOT NULL
582→    GROUP BY error_pattern
583→    ORDER BY occurrences DESC
584→    LIMIT 20
585→  `;
586→
587→	return queryClickhouse<ProjectError>(query);
588→}
