  1→import type {
  2→	ModelTokensTrendData,
  3→	OverviewKPIs,
  4→	UsageTrendData,
  5→} from "@rudel/api-routes";
  6→import { user } from "@rudel/sql-schema";
  7→import { eq } from "drizzle-orm";
  8→import {
  9→	buildAbsoluteDateFilter,
 10→	buildDateFilter,
 11→	escapeString,
 12→	queryClickhouse,
 13→} from "../clickhouse.js";
 14→import { db } from "../db.js";
 15→
 16→export interface Insight {
 17→	type: "trend" | "performer" | "alert" | "info";
 18→	severity: "positive" | "warning" | "negative" | "info";
 19→	message: string;
 20→	link: string;
 21→}
 22→
 23→/**
 24→ * Get overview KPI counts: distinct users, sessions, projects, subagents, skills, slash commands
 25→ */
 26→export async function getOverviewKPIs(
 27→	orgId: string,
 28→	startDate: string,
 29→	endDate: string,
 30→): Promise<OverviewKPIs> {
 31→	const org = escapeString(orgId);
 32→	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);
 33→
 34→	const query = `
 35→    SELECT
 36→      uniq(user_id) as distinct_users,
 37→      count() as distinct_sessions,
 38→      uniq(if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))) as distinct_projects,
 39→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN subagent_types as val WHERE ${buildAbsoluteDateFilter(startDate, endDate)} AND organization_id = '${org}' AND val != '') as distinct_subagents,
 40→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN skills as val WHERE ${buildAbsoluteDateFilter(startDate, endDate)} AND organization_id = '${org}' AND val != '') as distinct_skills,
 41→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN slash_commands as val WHERE ${buildAbsoluteDateFilter(startDate, endDate)} AND organization_id = '${org}' AND val != '') as distinct_slash_commands,
 42→      (SELECT count() FROM rudel.session_analytics WHERE organization_id = '${org}') as total_sessions
 43→    FROM rudel.session_analytics
 44→    WHERE ${dateFilter}
 45→      AND organization_id = '${org}'
 46→  `;
 47→
 48→	const result = await queryClickhouse<OverviewKPIs>(query);
 49→	const row = result[0];
 50→	if (!row) {
 51→		return {
 52→			distinct_users: 0,
 53→			distinct_sessions: 0,
 54→			distinct_projects: 0,
 55→			distinct_subagents: 0,
 56→			distinct_skills: 0,
 57→			distinct_slash_commands: 0,
 58→			total_sessions: 0,
 59→		};
 60→	}
 61→	// ClickHouse returns UInt64 as strings when output_format_json_quote_64bit_integers is true (the default)
 62→	return {
 63→		distinct_users: Number(row.distinct_users),
 64→		distinct_sessions: Number(row.distinct_sessions),
 65→		distinct_projects: Number(row.distinct_projects),
 66→		distinct_subagents: Number(row.distinct_subagents),
 67→		distinct_skills: Number(row.distinct_skills),
 68→		distinct_slash_commands: Number(row.distinct_slash_commands),
 69→		total_sessions: Number(row.total_sessions),
 70→	};
 71→}
 72→
 73→/**
 74→ * Get token usage broken down by model and day
 75→ */
 76→export async function getModelTokensTrend(
 77→	orgId: string,
 78→	startDate: string,
 79→	endDate: string,
 80→): Promise<ModelTokensTrendData[]> {
 81→	const org = escapeString(orgId);
 82→	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);
 83→
 84→	const query = `
 85→    SELECT
 86→      toDate(session_date) as date,
 87→      model_used as model,
 88→      sum(total_tokens) as total_tokens,
 89→      sum(input_tokens) as input_tokens,
 90→      sum(output_tokens) as output_tokens
 91→    FROM rudel.session_analytics
 92→    WHERE ${dateFilter}
 93→      AND organization_id = '${org}'
 94→      AND model_used != ''
 95→      AND model_used != 'unknown'
 96→    GROUP BY date, model
 97→    ORDER BY date ASC, total_tokens DESC
 98→  `;
 99→
100→	return queryClickhouse<ModelTokensTrendData>(query);
101→}
102→
103→/**
104→ * Get detailed usage trend data aggregated by day
105→ */
106→export async function getUsageTrendDetailed(
107→	orgId: string,
108→	startDate: string,
109→	endDate: string,
110→): Promise<UsageTrendData[]> {
111→	const org = escapeString(orgId);
112→	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);
113→
114→	const query = `
115→    SELECT
116→      toDate(session_date) as date,
117→      count() as sessions,
118→      uniq(user_id) as active_users,
119→      round(sum(actual_duration_min) / 60, 2) as total_hours,
120→      sum(total_tokens) as total_tokens
121→    FROM rudel.session_analytics
122→    WHERE ${dateFilter}
123→      AND organization_id = '${org}'
124→    GROUP BY date
125→    ORDER BY date ASC
126→  `;
127→
128→	return queryClickhouse<UsageTrendData>(query);
129→}
130→
131→/**
132→ * Generate rule-based insights from current data
133→ */
134→export async function getOverviewInsights(
135→	orgId: string,
136→	startDate: string,
137→	endDate: string,
138→): Promise<Insight[]> {
139→	const org = escapeString(orgId);
140→	const insights: Insight[] = [];
141→	const periodMs = new Date(endDate).getTime() - new Date(startDate).getTime();
142→	const prevEnd = new Date(new Date(startDate).getTime() - 1);
143→	const prevStart = new Date(prevEnd.getTime() - periodMs);
144→	const prevStartStr = prevStart.toISOString().slice(0, 10);
145→	const prevEndStr = prevEnd.toISOString().slice(0, 10);
146→
147→	const currentPeriodQuery = `
148→    SELECT
149→      count() as total_sessions,
150→      uniq(user_id) as total_users,
151→      round(avg(actual_duration_min), 2) as avg_duration_min
152→    FROM rudel.session_analytics
153→    WHERE ${buildAbsoluteDateFilter(startDate, endDate)}
154→      AND organization_id = '${org}'
155→  `;
156→
157→	const previousPeriodQuery = `
158→    SELECT
159→      count() as total_sessions,
160→      uniq(user_id) as total_users,
161→      round(avg(actual_duration_min), 2) as avg_duration_min
162→    FROM rudel.session_analytics
163→    WHERE ${buildAbsoluteDateFilter(prevStartStr, prevEndStr)}
164→      AND organization_id = '${org}'
165→  `;
166→
167→	interface PeriodStats {
168→		total_sessions: number;
169→		total_users: number;
170→		avg_duration_min: number;
171→	}
172→
173→	const [currentData, previousData] = await Promise.all([
174→		queryClickhouse<PeriodStats>(currentPeriodQuery),
175→		queryClickhouse<PeriodStats>(previousPeriodQuery),
176→	]);
177→
178→	const current = currentData[0];
179→	const previous = previousData[0] || { total_sessions: 0 };
180→
181→	// Insight 1: Session trend analysis
182→	if (current && previous) {
183→		const sessionChange =
184→			previous.total_sessions > 0
185→				? ((current.total_sessions - previous.total_sessions) /
186→						previous.total_sessions) *
187→					100
188→				: 0;
189→
190→		if (Math.abs(sessionChange) >= 10) {
191→			const direction = sessionChange > 0 ? "up" : "down";
192→			const severity = sessionChange > 0 ? "positive" : "warning";
193→			insights.push({
194→				type: "trend",
195→				severity,
196→				message: `Team activity ${direction} ${Math.abs(sessionChange).toFixed(1)}% this week`,
197→				link: "/dashboard/team",
198→			});
